-- 사용자 업로드 엑셀(요일×시프트 그리드)을 cs_assignments 로 적재.
-- 멱등: cs_schedules 2026-05 행 보장 -> 해당 스케줄 기존 배정 DELETE -> 재적재.
-- 배정 249건 (근무 229 · 휴무/반차 20) / 30일
-- 호환: MySQL 8.0
-- ═══════════════════════════════════════════════════════════════════

SELECT UUID(), 2026, 5, '2026년 5월 근무표', 'published', 'excel' FROM dual
WHERE NOT EXISTS (SELECT 1 FROM cs_schedules WHERE year=2026 AND month=5);

SET @sched := (SELECT id FROM cs_schedules WHERE year=2026 AND month=5 LIMIT 1);

SET @L01 := (SELECT id FROM cs_shift_slots WHERE code='L01' LIMIT 1);
SET @L02 := (SELECT id FROM cs_shift_slots WHERE code='L02' LIMIT 1);
SET @L03 := (SELECT id FROM cs_shift_slots WHERE code='L03' LIMIT 1);
SET @L04 := (SELECT id FROM cs_shift_slots WHERE code='L04' LIMIT 1);
SET @L05 := (SELECT id FROM cs_shift_slots WHERE code='L05' LIMIT 1);
SET @L06 := (SELECT id FROM cs_shift_slots WHERE code='L06' LIMIT 1);
SET @L07 := (SELECT id FROM cs_shift_slots WHERE code='L07' LIMIT 1);
SET @L08 := (SELECT id FROM cs_shift_slots WHERE code='L08' LIMIT 1);
SET @L09 := (SELECT id FROM cs_shift_slots WHERE code='L09' LIMIT 1);
SET @L10 := (SELECT id FROM cs_shift_slots WHERE code='L10' LIMIT 1);
SET @L11 := (SELECT id FROM cs_shift_slots WHERE code='L11' LIMIT 1);
SET @L12 := (SELECT id FROM cs_shift_slots WHERE code='L12' LIMIT 1);
SET @L13 := (SELECT id FROM cs_shift_slots WHERE code='L13' LIMIT 1);

DELETE FROM cs_assignments WHERE schedule_id = @sched;


